import{_ as i,c as t,o as a,a2 as s}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Troubleshooting (PetReminder on macOS)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1781417556000}'),o={name:"guide/troubleshooting.md"};function r(n,e,l,p,h,d){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="troubleshooting-petreminder-on-macos" tabindex="-1">Troubleshooting (PetReminder on macOS) <a class="header-anchor" href="#troubleshooting-petreminder-on-macos" aria-label="Permalink to &quot;Troubleshooting (PetReminder on macOS)&quot;">​</a></h1><p>This page collects common problems for macOS users and how to resolve them.</p><h2 id="application-won-t-start-or-crashes-on-launch" tabindex="-1">Application won&#39;t start or crashes on launch <a class="header-anchor" href="#application-won-t-start-or-crashes-on-launch" aria-label="Permalink to &quot;Application won&#39;t start or crashes on launch&quot;">​</a></h2><p>Symptoms: PetReminder does not open, crashes immediately, or shows an unexpected error.</p><p>Steps to try:</p><ol><li>Ensure your macOS version meets the minimum requirements (Monterey 12+ recommended).</li><li>Quit and relaunch the app.</li><li>Reboot your Mac.</li><li>If the app was downloaded from GitHub Releases, try downloading a newer build or the notarized build.</li><li>If problems persist, collect logs (see below) and open an issue on the project repository.</li></ol><h2 id="pet-not-appearing-on-reminders" tabindex="-1">Pet not appearing on reminders <a class="header-anchor" href="#pet-not-appearing-on-reminders" aria-label="Permalink to &quot;Pet not appearing on reminders&quot;">​</a></h2><p>Symptoms: Reminder fires but no pet appears.</p><p>Checklist:</p><ol><li>Ensure <strong>Notifications</strong> permission is granted (System Settings → Privacy &amp; Security → Notifications).</li><li>Check that a pet is selected in Settings → Pet.</li><li>Try restarting the app after changing pet settings.</li></ol><h2 id="iap-purchase-not-showing" tabindex="-1">IAP purchase not showing <a class="header-anchor" href="#iap-purchase-not-showing" aria-label="Permalink to &quot;IAP purchase not showing&quot;">​</a></h2><p>Symptoms: You purchased a pet but it&#39;s not available in the app.</p><p>Fixes:</p><ol><li>Ensure you&#39;re signed into the same Apple ID used for purchase.</li><li>Go to <strong>Pets</strong> tab and tap <strong>Restore Purchases</strong>.</li><li>If still missing, try restarting the app.</li><li>Contact support if the issue persists — include your purchase receipt.</li></ol><h2 id="permission-related-issues" tabindex="-1">Permission-related issues <a class="header-anchor" href="#permission-related-issues" aria-label="Permalink to &quot;Permission-related issues&quot;">​</a></h2><p>If a feature prompts for permission but doesn&#39;t work after granting it:</p><ol><li>Quit the app and reopen it after granting the permission.</li><li>If needed, reset the permission prompt with <code>tccutil</code> (see the <a href="./permissions.html">Permissions guide</a>).</li></ol><h2 id="performance-issues" tabindex="-1">Performance issues <a class="header-anchor" href="#performance-issues" aria-label="Permalink to &quot;Performance issues&quot;">​</a></h2><p>If the app is slow or the pet animation is laggy:</p><ol><li>Close other heavy applications.</li><li>Reduce animation quality in Settings → Pet.</li><li>Disable sound effects if they cause stutter.</li></ol><h2 id="view-logs" tabindex="-1">View logs <a class="header-anchor" href="#view-logs" aria-label="Permalink to &quot;View logs&quot;">​</a></h2><p>To troubleshoot crashes or issues, application logs are the most useful artifact. In sandboxed (App Store) builds, check:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Containers/com.w3cub.reminder/Data/Library/Logs/reminder/reminder.log</span></span></code></pre></div><p>When running a development build, logs may be in the project directory (<code>./src-tauri/reminder.log</code>) or printed to the console.</p><h2 id="resetting-the-app" tabindex="-1">Resetting the app <a class="header-anchor" href="#resetting-the-app" aria-label="Permalink to &quot;Resetting the app&quot;">​</a></h2><p>To reset settings and clear local data:</p><ol><li>Quit PetReminder</li><li>Remove the container (be careful—this deletes all reminders and settings):</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Containers/com.w3cub.reminder</span></span></code></pre></div><ol start="3"><li>Reopen PetReminder and reconfigure.</li></ol><h2 id="report-an-issue" tabindex="-1">Report an issue <a class="header-anchor" href="#report-an-issue" aria-label="Permalink to &quot;Report an issue&quot;">​</a></h2><p>When opening an issue, include:</p><ul><li>macOS version (Apple menu → About This Mac)</li><li>PetReminder version (PetReminder → About)</li><li>Steps to reproduce</li><li>Logs (attach <code>reminder.log</code> if available)</li></ul><p>This helps maintainers identify and fix the problem faster.</p>',33)])])}const m=i(o,[["render",r]]);export{u as __pageData,m as default};
